import autogen

from vex_sdk import VexClient

# Initialize Vex client
vex = VexClient(api_key="vex_your_key")

@vex.filter(framework="autogen")
def compliance_filter(message, context):
    # Check for infinite loops
    if context.get('turn_count', 0) > 50:
        return {'block': True, 'reason': 'Max turns exceeded'}

    # PII detection
    if vex.detect_pii(message):
        return {'block': True, 'reason': 'PII detected'}

    # Token budget check
    if context.get('tokens_used', 0) > 5000:
        return {'block': True, 'reason': 'Token limit exceeded'}

    return {'allow': True}

# Register with AutoGen
config_list = [{"model": "gpt-4", "api_key": "key"}]

llm_config = {"config_list": config_list, "reply_filter": [compliance_filter]}

user_proxy = autogen.UserProxyAgent(name="user", code_execution_config=False)
group_chat = autogen.GroupChat(agents=[user_proxy], messages=[], llm_config=llm_config)

def tenant_isolation_filter(message, context):
    tenant_id = context.get('tenant_id')
    data_residency = context.get('data_residency', 'us')

    # Validate tenant context
    if not tenant_id:
        return {'block': True, 'reason': 'Missing tenant_id'}

    # Data residency check
    if 'eu' in message.lower() and data_residency != 'eu':
        return {'block': True, 'reason': 'Data residency violation'}

    # Cross-tenant reference detection
    if f"tenant:{tenant_id}" not in message:
        return {'block': True, 'reason': 'Cross-tenant data access'}

    # Log compliant interaction
    vex.log({
        'tenant_id': tenant_id,
        'action': 'agent_reply',
        'message_hash': vex.hash(message)
    })

    return {'allow': True}

# Register tenant filter
vex.register_filter(tenant_isolation_filter, priority=1)
